// generar_250_fix_validacion_medicamento_lista.js
// CHIQUI Entre Señales — Fix: modo lista de medicamentos no debe pedir nombre
//
// Bug del 249: al elegir un medicamento existente en el mini-modal
// (modo lista con checks) y tocar "Confirmar toma de hoy", el modal
// respondía "Escribe el nombre para continuar" — la validación de
// nombre corría siempre, aunque en modo lista el nombre no aplica
// (la elección es el radio-button).
//
// Fix: la validación de nombre solo se ejecuta cuando NO estamos en
// modo lista de medicamento. Modo lista requiere solo que haya un
// medicamento seleccionado (lo que ya validaba la rama de guardado).
//
// Solo reescribe app/registro-diario/page.tsx. No hay SQL.
//
// Uso:
//   node generar_250_fix_validacion_medicamento_lista.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/registro-diario/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
